// Time:  O(n^2)
// Space: O(n^2)

class Solution {
public:
    bool canCross(vector<int>& stones) {
        if (stones[1] != 1) {
            return false;
        }

        unordered_map<int, unordered_set<int>> last_jump_units;
        for (const auto& s: stones) {
            last_jump_units.emplace(s, {unordered_set<int>()});
        }
        last_jump_units[1].emplace(1);

        for (int i = 0; i + 1 < stones.size(); ++i) {
            for (const auto& j : last_jump_units[stones[i]]) {
                for (const auto& k : {j - 1, j, j + 1}) {
                    if (k > 0 && last_jump_units.count(stones[i] + k)) {
                        last_jump_units[stones[i] + k].emplace(k);
                    }
                }
            }
        }

        return !last_jump_units[stones.back()].empty();
    }
};

# Time:  O(n^2)
# Space: O(n^2)

class Solution(object):
    def canCross(self, stones):
        """
        :type stones: List[int]
        :rtype: bool
        """
        if stones[1] != 1:
            return False

        last_jump_units = {s: set() for s in stones}
        last_jump_units[1].add(1)
        for s in stones[:-1]:
            for j in last_jump_units[s]:
                for k in (j-1, j, j+1):
                    if k > 0 and s+k in last_jump_units:
                        last_jump_units[s+k].add(k)
        return bool(last_jump_units[stones[-1]])
